import { AsyncDuckDB } from '@duckdb/duckdb-wasm';
import { BinOptions } from '@observablehq/plot';
import { JSDOM } from 'jsdom';
import { Markish } from '@observablehq/plot';
import { MarkOptions } from '@observablehq/plot';
import * as Plot from '@observablehq/plot';
import { PlotOptions } from '@observablehq/plot';
import { RenderFunction } from '@observablehq/plot';
import { StackOptions } from '@observablehq/plot';

declare type Aggregate = "sum" | "avg" | "count" | "max" | "min" | "median" | "mode" | "stddev" | "variance" | false;

declare interface AllMarkOptions extends MarkOptions, StackOptions, BinOptions {
}

declare type BasicColumnType = "string" | "number" | "date" | undefined;

declare type ChartType = "dot" | "areaY" | "line" | "barX" | "barY" | "text" | "tickX" | "tickY" | "rectX" | "rectY" | "treemap" | "circlePack" | "image" | "pie" | undefined;

declare type ColumnType = string | string[];

declare type Config = {
    xLabelDisplay?: boolean;
    yLabelDisplay?: boolean;
    tip?: boolean;
    tipLabels?: {
        x?: string;
        y?: string;
        color?: string;
    };
    tipValues?: {
        x?: (d: Indexable, i: number) => string;
        y?: (d: Indexable, i: number) => string;
        color?: (d: Indexable, i: number) => string;
    };
    tipMark?: {
        type: Exclude<ChartType, "circlePack" | "treemap" | "pie">;
        options: MarkOptions;
    };
    displayPiePerentages?: boolean;
    donut?: boolean;
    autoMargin?: boolean;
    aggregate?: Aggregate;
    interactiveLegend?: boolean;
    percent?: boolean;
    onClick?: (event: Event, value: unknown) => void;
    customRender?: RenderFunction;
};

declare interface Data extends Array<Indexable> {
    types?: {
        [key: string]: BasicColumnType;
    };
    labels?: {
        x?: string;
        y?: string;
        series?: string;
    };
}

declare type DefinedChartType = Exclude<ChartType, undefined>;

export declare class DuckPlot {
    private _ddb;
    private _table;
    private _catalog;
    private _x;
    private _y;
    private _fy;
    private _fx;
    private _r;
    private _text;
    private _color;
    private _mark;
    private _options;
    private _jsdom;
    private _font;
    private _isServer;
    private _document;
    private _newDataProps;
    private _data;
    private _rawData;
    private _markColumn;
    private _config;
    private _query;
    private _description;
    private _queries;
    private _id;
    private _sorts;
    private _hasLegend;
    private _legendType;
    plotObject: ((HTMLElement | SVGSVGElement) & Plot.Plot) | undefined;
    visibleSeries: string[];
    filteredData: Data | undefined;
    chartContainer: HTMLElement | null;
    seriesDomain: number[];
    constructor(ddb?: AsyncDuckDB | null, // Allow null so you can work with raw data
        { jsdom, font }?: {
        jsdom?: JSDOM;
        font?: any;
    });
    table(): string;
    table(table: string): this;
    catalog(): string;
    catalog(catalog: string): this;
    query(): string;
    query(query: string): this;
    x(): PlotProperty<"x">;
    x(column: IncomingColumType, options?: PlotOptions["x"]): this;
    y(): PlotProperty<"y">;
    y(column: IncomingColumType, options?: PlotOptions["y"]): this;
    color(): PlotProperty<"color">;
    color(column: IncomingColumType, options?: PlotOptions["color"]): this;
    fy(): PlotProperty<"fy">;
    fy(column: IncomingColumType, options?: PlotOptions["fy"]): this;
    fx(): PlotProperty<"fx">;
    fx(column: IncomingColumType, options?: PlotOptions["fx"]): this;
    r(): PlotProperty<"r">;
    r(column: IncomingColumType, options?: PlotOptions["r"]): this;
    text(): {
        column: string;
    };
    text(column: IncomingColumType): this;
    mark(): MarkProperty;
    mark(type: ChartType, options?: MarkProperty["options"]): this;
    options(): PlotOptions;
    options(opts: PlotOptions): this;
    config(): Config;
    config(config: Config): this;
    rawData(): Data;
    rawData(data?: Data, types?: {
        [key: string]: BasicColumnType;
    }): this;
    markColumn(): MarkColumnProperty;
    markColumn(column: string, options?: MarkColumnProperty["options"]): this;
    prepareData(): Promise<Data>;
    derivePlotOptions(): PlotOptions;
    getAllMarkOptions(): Markish[];
    setSorts(): void;
    setLegend(plotOptions: Plot.PlotOptions): void;
    render(newLegend?: boolean): Promise<SVGElement | HTMLElement | null>;
    get newDataProps(): boolean;
    set newDataProps(newValue: boolean);
    get ddb(): AsyncDuckDB | null | undefined;
    get isServer(): boolean;
    get document(): Document;
    get font(): any;
    get jsdom(): any;
    get sorts(): Sorts;
    id(): string;
    data(): Data;
    describe(): string;
    queries(): QueryMap | undefined;
    get hasLegend(): boolean | undefined;
    get legendType(): Plot.ScaleType | "categorical" | "continuous" | undefined;
}

declare type IncomingColumType = ColumnType | false | null;

declare type Indexable = {
    [key: string]: any;
};

declare type MarkColumnProperty = {
    column?: string;
    options?: Partial<Record<DefinedChartType, AllMarkOptions>>;
};

declare type MarkProperty = {
    type?: ChartType;
    options?: AllMarkOptions;
};

declare type PlotProperty<T extends keyof PlotOptions> = {
    column: ColumnType;
    options?: PlotOptions[T];
};

declare type QueryMap = {
    [key: string]: string;
};

declare type Sorts = {
    x?: {
        domain: string[];
    };
    y?: {
        domain: string[];
    };
    fx?: {
        domain: string[];
    };
    fy?: {
        domain: string[];
    };
    series?: {
        domain: string[];
    };
};

export { }
